from pathlib import Path
import re

WORKSPACE_ROOT = Path("/workspace/project").resolve()

# Patterns that are always denied regardless of workspace membership
DENIED_PATTERNS = [
    re.compile(r"\.env(\.|$)", re.IGNORECASE),
    re.compile(r"secret", re.IGNORECASE),
    re.compile(r"password", re.IGNORECASE),
    re.compile(r"id_rsa"),
    re.compile(r"\.pem$"),
    re.compile(r"credentials"),
]

DENIED_PREFIXES = ("/etc", "/proc", "/sys", "/dev", "/root", "/var/run")

class FileAccessError(Exception):
    pass

def validate_path(requested: str, must_exist: bool = False) -> Path:
    """Resolve path and assert it is inside WORKSPACE_ROOT.

    Raises FileAccessError on any violation.
    """
    # Resolve to absolute (follows symlinks)
    try:
        resolved = (WORKSPACE_ROOT / requested).resolve()
    except OSError as e:
        raise FileAccessError(f"Cannot resolve path: {e}")

    # Must be inside workspace
    try:
        resolved.relative_to(WORKSPACE_ROOT)
    except ValueError:
        raise FileAccessError(
            f"Path '{requested}' resolves outside workspace root."
        )

    # Block sensitive system paths (belt-and-suspenders after resolve)
    for prefix in DENIED_PREFIXES:
        if str(resolved).startswith(prefix):
            raise FileAccessError(f"Access to '{prefix}' is denied.")

    # Block sensitive filename patterns
    for part in resolved.parts:
        for pattern in DENIED_PATTERNS:
            if pattern.search(part):
                raise FileAccessError(
                    f"Filename '{part}' matches a sensitive pattern."
                )

    # Symlink check: target must also be inside workspace
    if resolved.is_symlink():
        real = resolved.readlink().resolve()
        try:
            real.relative_to(WORKSPACE_ROOT)
        except ValueError:
            raise FileAccessError(
                f"Symlink '{requested}' points outside workspace."
            )

    if must_exist and not resolved.exists():
        raise FileAccessError(f"File not found: {requested}")

    return resolved

def list_dir(
    path: str = ".",
    recursive: bool = False,
    max_entries: int = 500,
) -> dict:
    """List directory contents inside the workspace.

    Returns a JSON-serialisable tree structure.
    Caps at max_entries to prevent context flooding on large repos.
    """
    resolved = validate_path(path, must_exist=True)
    if not resolved.is_dir():
        raise FileAccessError(f"'{path}' is not a directory.")

    entries: list[dict] = []
    count = 0

    if recursive:
        for root, dirs, files in os.walk(resolved):
            # Skip hidden and common noise directories
            dirs[:] = [d for d in dirs if not d.startswith(".") and d not in ("node_modules", "__pycache__", ".git")]
            root_path = Path(root)
            for name in sorted(files):
                if count >= max_entries:
                    break
                fp = root_path / name
                entries.append({
                    "path": str(fp.relative_to(WORKSPACE_ROOT)),
                    "type": "file",
                    "size": fp.stat().st_size,
                })
                count += 1
            if count >= max_entries:
                break
    else:
        for item in sorted(resolved.iterdir()):
            if count >= max_entries:
                break
            stat = item.stat()
            entries.append({
                "path": str(item.relative_to(WORKSPACE_ROOT)),
                "type": "dir" if item.is_dir() else "file",
                "size": stat.st_size if item.is_file() else None,
            })
            count += 1

    return {
        "path": str(resolved.relative_to(WORKSPACE_ROOT)),
        "entries": entries,
        "truncated": count >= max_entries,
    }

import anthropic, json

client = anthropic.Anthropic()

FILE_TOOLS = [
    {
        "name": "read_file",
        "description": "Read a text file from the workspace. Supports pagination via offset/limit for large files.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "Relative path from workspace root (e.g. 'src/main.py')"},
                "offset": {"type": "integer", "description": "Byte offset to start reading from (default 0)"},
                "limit": {"type": "integer", "description": "Max bytes to return (default 8192)"},
            },
            "required": ["path"],
        },
    },
    {
        "name": "write_file",
        "description": "Write or overwrite a text file in the workspace. Creates parent directories as needed.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "Relative path for the file"},
                "content": {"type": "string", "description": "Full text content to write"},
            },
            "required": ["path", "content"],
        },
    },
    {
        "name": "list_dir",
        "description": "List files and directories. Set recursive=true for a full tree.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string", "description": "Directory to list (default '.')"},
                "recursive": {"type": "boolean", "description": "Include subdirectories recursively"},
            },
            "required": [],
        },
    },
]

DISPATCHER = {
    "read_file":  lambda i: read_file(**i),
    "write_file": lambda i: write_file(**i),
    "list_dir":   lambda i: list_dir(**i),
}

def run_file_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]
    while True:
        response = client.messages.create(
            model="claude-opus-4-8", max_tokens=2048,
            tools=FILE_TOOLS, messages=messages,
        )
        if response.stop_reason == "end_turn":
            return next((b.text for b in response.content if b.type == "text"), "")
        tool_results = []
        for b in response.content:
            if b.type == "tool_use":
                try:
                    result = DISPATCHER[b.name](b.input)
                    content = json.dumps(result)
                except FileAccessError as e:
                    content = json.dumps({"error": str(e)})
                tool_results.append({"type": "tool_result", "tool_use_id": b.id, "content": content})
        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})
